const sf = $('PG: SHOP_FAILED Stats').first().json;
const rev = $('PG: Revenue Today').first().json;
const cat = $('PG: Catalog Health').first().json;
const details = $('PG: SHOP_FAILED Details').all().map(i=>i.json);
const failPct = parseFloat(sf.fail_pct||0);
const anomalies = [];
if (failPct > 30) anomalies.push('SHOP_FAILED ' + failPct + '% КРИТИЧНО');
else if (failPct > 10) anomalies.push('SHOP_FAILED ' + failPct + '% выше нормы');
if (parseInt(cat.oos_visible||0) > 10000) anomalies.push('OOS видны: ' + cat.oos_visible);
if (parseInt(cat.pending_mod||0) > 2000) anomalies.push('Модерация: ' + cat.pending_mod);
const today = new Date().toISOString().slice(0,10);
const failList = details.slice(0,3).map(d => '- ' + (d.product||d.external_order_id||'?')).join('; ');
const prompt = 'Head of Product GG Exchange. Утренний брифинг инвестору. Данные ' + today + ': YM заказы 24ч: всего ' + sf.total_ym + ', SHOP_FAILED ' + sf.shop_failed + ' (' + sf.fail_pct + '%), успешных ' + sf.success + '. Выручка сегодня EUR ' + (rev.eur_today||0) + ' RUB ' + (rev.rub_today||0) + '. 30 дней EUR ' + (rev.eur_30d||0) + '. Каталог: активных ' + cat.active + ', OOS ' + cat.oos_visible + ', модерация ' + cat.pending_mod + '. ' + (failList ? 'SHOP_FAILED товары: ' + failList + '. ' : '') + (anomalies.length ? 'Аномалии: ' + anomalies.join(', ') + '.' : 'Аномалий нет.') + ' Формат: 3-4 предложения. Числа потом проблема потом действие. Без вводных слов.';
return [{ json: { prompt, sf, rev, cat, anomalies, failPct } }];

const ctx = $('Code: Build Context').first().json;
const resp = $('Claude: Analyze').first().json;
const analysis = (resp && resp.content && resp.content[0]) ? resp.content[0].text : 'Анализ недоступен';
const icon = ctx.failPct > 30 ? '🚨' : ctx.anomalies.length > 0 ? '⚠️' : '✅';
const date = new Date().toLocaleDateString('ru-RU');
const msg = icon + ' GG Exchange ' + date + ' ' + ctx.sf.fail_pct + '% SHOP_FAILED ' + ctx.sf.shop_failed + '/' + ctx.sf.total_ym + ' YM | EUR ' + (ctx.rev.eur_today||0) + ' сегодня | EUR ' + (ctx.rev.eur_30d||0) + ' 30д | каталог ' + ctx.cat.active + ' 🤖 ' + analysis;
return [{ json: { msg } }];

